		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		List<RuleApplication> applications = rule.apply(rootExpression, OptimizationGoal.root(),
				new RuleContext(memo, costModel, CascadesTelemetry.NO_OP, null));

		assertFalse(applications.stream().anyMatch(application -> hasProofFact(application, "correlatedExists")),
				"A schema-dropping semi-filter cannot remove a binding consumed by the surrounding EXISTS");
